use std::collections::VecDeque;

struct PacketStreamSimulator {
    queue: VecDeque<String>,
}

impl PacketStreamSimulator {
    fn new() -> Self {
        PacketStreamSimulator { queue: VecDeque::new() }
    }

    fn enqueue_packets(&mut self, packets: Vec<&str>) {
        for packet in packets {
            self.queue.push_back(packet.to_string());
        }
    }

    fn next_packet(&mut self) -> Option<String> {
        self.queue.pop_front()
    }

    fn is_empty(&self) -> bool {
        self.queue.is_empty()
    }
}

fn run_simulation_test() {
    let mut simulator = PacketStreamSimulator::new();
    simulator.enqueue_packets(vec!["SYN_PACKET", "ACK_PACKET", "DISCONNECT_EVENT"]);

    println!("Starting packet stream simulation...");

    if let Some(packet) = simulator.next_packet() {
        println!("Processed first event: {}", packet);
    }

    if let Some(packet) = simulator.next_packet() {
        println!("Processed second event: {}", packet);
    }

    if let Some(packet) = simulator.next_packet() {
        println!("Processed final event: {}", packet);
    }

    assert!(simulator.is_empty());
    println!("Simulation finished successfully.");
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Hash, Deserialize, Serialize)]
struct SchemaId(String);

#[derive(Debug, Clone, Deserialize, Serialize)]
struct TestFixture {
    schema_id: SchemaId,
    expected_diff: String,
    is_valid: bool,
}

fn load_fixtures() -> HashMap<SchemaId, TestFixture> {
    let mut map = HashMap::new();
    let fixture1 = TestFixture {
        schema_id: SchemaId("user.proto".to_string()),
        expected_diff: "field_a: added".to_string(),
        is_valid: true,
    };
    let fixture2 = TestFixture {
        schema_id: SchemaId("address.proto".to_string()),
        expected_diff: "type_b: changed".to_string(),
        is_valid: false,
    };
    map.insert(fixture1.schema_id.clone(), fixture1);
    map.insert(fixture2.schema_id.clone(), fixture2);
    map
}

fn run_validator_test(id: &SchemaId, fixtures: &HashMap<SchemaId, TestFixture>) -> Result<(), Box<dyn std::error::Error>> {
    let fixture = fixtures.get(id).ok_or_else(|| format!("No fixture found for ID {}", id.0))?;

    if !fixture.is_valid {
        println!("Test failed as expected for {}. Diff: {}", id.0, &fixture.expected_diff);
        return Ok(()) 
    }

    println!("Successfully validated schema {} against fixture.", id.0);
    Ok(()) 
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let fixtures = load_fixtures();
    let user_id = SchemaId("user.proto".to_string());
    let address_id = SchemaId("address.proto".to_string());

    run_validator_test(&user_id, &fixtures)?;
    run_validator_test(&address_id, &fixtures)?;

    Ok(()) 
}

use std::collections::HashMap;

struct RaftNodeState {
    id: u32,
    term: u64,
    voted_for: Option<u32>,
    log_entries: Vec<String>,
}

impl RaftNodeState {
    fn new(node_id: u32) -> Self {
        RaftNodeState {
            id: node_id,
            term: 0,
            voted_for: None,
            log_entries: Vec::new(),
        }
    }

    fn apply_config(&mut self, new_term: u64, leader_id: u32) {
        self.term = new_term;
        self.voted_for = Some(leader_id);
    }

    fn print_state(&self) -> HashMap<String, String> {
        let mut map = HashMap::new();
        map.insert("ID".to_string(), self.id.to_string());
        map.insert("Term".to_string(), self.term.to_string());
        map.insert("LogSize".to_string(), self.log_entries.len().to_string());
        map
    }
}

fn setup_test_cluster(initial_nodes: &[u32]) -> Vec<RaftNodeState> {
    let mut cluster = Vec::new();
    for &id in initial_nodes {
        cluster.push(RaftNodeState::new(id));
    }
    cluster
}

fn main() {
    let config_ids = vec![10, 20, 30];
    let mut cluster_state = setup_test_cluster(&config_ids);

    for node in &mut cluster_state {
        node.apply_config(5, 10);
    }

    println!("--- Initialized Cluster State ---");
    let final_states: Vec<HashMap<String, String>> = cluster_state.iter().map(|s| s.print_state()).collect();

    for state in final_states {
        println!("{:?}", state);
    }
}

use std::collections::VecDeque;
use std::sync::{Arc, Mutex};

struct StateSimulator {
    event_queue: Arc<Mutex<VecDeque<String>>>, 
}

impl StateSimulator {
    fn new() -> Self {
        StateSimulator { 
            event_queue: Arc::new(Mutex::new(VecDeque::new())) 
        }
    }

    fn enqueue_event(&self, event: &str) {
        let mut queue = self.event_queue.lock().unwrap();
        queue.push_back(event.to_string());
    }

    fn process_next_event(&self) -> Option<String> {
        let mut queue = self.event_queue.lock().unwrap();
        if let Some(event) = queue.pop_front() {
            Some(event)
        } else {
            None
        }
    }
}

#[cfg(test)]
mod tests {
    use super::StateSimulator;

    fn setup_simulator() -> StateSimulator {
        StateSimulator::new()
    }

    #[test]
    fn test_event_stream_processing() {
        let simulator = setup_simulator();
        simulator.enqueue_event("UserLoggedIn:{\"user\":123}");
        simulator.enqueue_event("ViewOpened:{\"screen\":\"Home\"}");

        let event1 = simulator.process_next_event().expect("Expected first event, got nothing.");
        assert!(event1.contains("UserLoggedIn"));

        let event2 = simulator.process_next_event().expect("Expected second event, got nothing.");
        assert!(event2.contains("ViewOpened"));

        let event3 = simulator.process_next_event();
        assert!(event3.is_none());
    }
}

use std::collections::HashSet;

struct TelemetryStream {
    timestamps: Vec<i64>,
}

impl TelemetryStream {
    fn new(timestamps: Vec<i64>) -> Self {
        TelemetryStream { timestamps }
    }

    fn check_integrity(&self, expected_count: usize) -> (bool, Vec<String>) {
        let mut seen = HashSet::new();
        let mut integrity_errors = Vec::new();
        let sorted_timestamps = self.timestamps.clone();
        let mut current_expected = sorted_timestamps.get(0).cloned().unwrap_or(-1);

        if sorted_timestamps.is_empty() {
            return (true, vec![String::from("No data received.")]);
        }

        for i in 0..sorted_timestamps.len() {
            let actual = sorted_timestamps[i];
            if seen.contains(&actual) {
                integrity_errors.push(format!("Duplicate timestamp detected: {}", actual));
            } else if i > 0 && actual > current_expected + 1000 { // Assuming a fixed small interval for simplicity in the test helper concept
                integrity_errors.push(format!("Potential gap: Expected around {}, got {}", current_expected, actual));
            }
            seen.insert(actual);
            current_expected = actual;
        }

        let passed = integrity_errors.is_empty();
        return (passed, integrity_errors);
    }
}
